"},{"function_name":"assinar_vistoria_publica","definition":"CREATE OR REPLACE FUNCTION public.assinar_vistoria_publica(p_token text, p_nome text, p_cpf text, p_email text, p_papel text, p_assinatura_url text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_vistoria_id uuid;
  v_vistoria_status text;
  v_assinatura_id uuid;
BEGIN
  SELECT id, status INTO v_vistoria_id, v_vistoria_status
  FROM vistorias
  WHERE link_publico_token = p_token;

  IF v_vistoria_id IS NULL THEN
    RETURN jsonb_build_object('error', 'Vistoria não encontrada');
  END IF;

  IF EXISTS (
    SELECT 1 FROM vistoria_assinaturas
    WHERE vistoria_id = v_vistoria_id
      AND email = p_email
      AND assinatura_url IS NOT NULL
  ) THEN
    RETURN jsonb_build_object('error', 'Este e-mail já assinou esta vistoria');
  END IF;

  INSERT INTO vistoria_assinaturas (
    vistoria_id, nome, papel, assinatura_url, email, cpf, assinado_em
  ) VALUES (
    v_vistoria_id, p_nome, p_papel, p_assinatura_url, p_email, p_cpf, NOW()
  ) RETURNING id INTO v_assinatura_id;

  UPDATE vistorias
  SET status = 'assinada', updated_at = NOW()
  WHERE id = v_vistoria_id;

  RETURN jsonb_build_object(
    'success', true,
    'assinatura_id', v_assinatura_id
  );
END;
$function$
"},{"function_name":"change_apartment","definition":"CREATE OR REPLACE FUNCTION public.change_apartment(p_user_id uuid, p_new_bloco_txt text, p_new_apto_txt text)
 RETURNS json
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_condo_id UUID;
  v_bloco_id UUID;
  v_apto_id UUID;
  v_unidade_id UUID;
  v_old_bloco TEXT;
  v_old_apto TEXT;
BEGIN
  -- 1. Buscar condomínio do morador
  SELECT condominio_id, bloco_txt, apto_txt
  INTO v_condo_id, v_old_bloco, v_old_apto
  FROM perfil
  WHERE id = p_user_id;

  IF v_condo_id IS NULL THEN
    RETURN json_build_object('success', false, 'error', 'Perfil não encontrado');
  END IF;

  -- 2. Se é o mesmo bloco+apto, não faz nada
  IF LOWER(TRIM(v_old_bloco)) = LOWER(TRIM(p_new_bloco_txt)) 
     AND LOWER(TRIM(v_old_apto)) = LOWER(TRIM(p_new_apto_txt)) THEN
    RETURN json_build_object('success', false, 'error', 'Você já está neste apartamento');
  END IF;

  -- 3. Validar: o bloco existe?
  SELECT id INTO v_bloco_id
  FROM blocos
  WHERE condominio_id = v_condo_id
    AND LOWER(TRIM(nome_ou_numero)) = LOWER(TRIM(p_new_bloco_txt));

  IF v_bloco_id IS NULL THEN
    RETURN json_build_object('success', false, 'error', 'Bloco não encontrado: ' || p_new_bloco_txt);
  END IF;

  -- 4. Validar: o apartamento existe?
  SELECT id INTO v_apto_id
  FROM apartamentos
  WHERE condominio_id = v_condo_id
    AND LOWER(TRIM(numero)) = LOWER(TRIM(p_new_apto_txt));

  IF v_apto_id IS NULL THEN
    RETURN json_build_object('success', false, 'error', 'Apartamento não encontrado: ' || p_new_apto_txt);
  END IF;

  -- 5. Validar: a unidade (bloco+apto) existe?
  SELECT id INTO v_unidade_id
  FROM unidades
  WHERE condominio_id = v_condo_id
    AND bloco_id = v_bloco_id
    AND apartamento_id = v_apto_id;

  IF v_unidade_id IS NULL THEN
    RETURN json_build_object('success', false, 'error', 'Unidade não encontrada para este bloco/apartamento');
  END IF;

  -- 6. Inativar vínculo(s) antigo(s)
  UPDATE unidade_perfil
  SET status = 'inativo',
      data_saida = now()
  WHERE perfil_id = p_user_id
    AND status = 'ativo';

  -- 7. Criar novo vínculo
  INSERT INTO unidade_perfil (perfil_id, unidade_id, status, data_entrada)
  VALUES (p_user_id, v_unidade_id, 'ativo', now())
  ON CONFLICT (perfil_id, unidade_id) DO UPDATE
  SET status = 'ativo', data_entrada = now(), data_saida = NULL;

  -- 8. Atualizar perfil
  UPDATE perfil
  SET bloco_txt = p_new_bloco_txt,
      apto_txt = p_new_apto_txt,
      status_aprovacao = 'pendente',
      updated_at = now()
  WHERE id = p_user_id;

  RETURN json_build_object(
    'success', true,
    'message', 'Apartamento alterado. Aguarde aprovação do síndico.',
    'old_bloco', v_old_bloco,
    'old_apto', v_old_apto,
    'new_bloco', p_new_bloco_txt,
    'new_apto', p_new_apto_txt
  );
END;
$function$
"},{"function_name":"change_user_password","definition":"CREATE OR REPLACE FUNCTION public.change_user_password(current_password text, new_password text)
 RETURNS json
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'extensions'
AS $function$
DECLARE
  v_uid UUID;
  v_stored_hash TEXT;
BEGIN
  v_uid := auth.uid();
  IF v_uid IS NULL THEN
    RETURN json_build_object('success', false, 'error', 'Não autenticado.');
  END IF;

  -- Validate new password
  IF LENGTH(new_password) < 4 THEN
    RETURN json_build_object('success', false, 'error', 'Nova senha deve ter no mínimo 4 dígitos.');
  END IF;

  -- Verify current password
  SELECT encrypted_password INTO v_stored_hash FROM auth.users WHERE id = v_uid;
  IF v_stored_hash IS NULL THEN
    RETURN json_build_object('success', false, 'error', 'Usuário não encontrado.');
  END IF;

  IF crypt(current_password, v_stored_hash) != v_stored_hash THEN
    RETURN json_build_object('success', false, 'error', 'Senha atual incorreta.');
  END IF;

  -- Update password
  UPDATE auth.users
  SET encrypted_password = crypt(new_password, gen_salt('bf')),
      updated_at = now()
  WHERE id = v_uid;

  RETURN json_build_object('success', true);

EXCEPTION WHEN OTHERS THEN
  RAISE WARNING 'change_user_password failed: %', SQLERRM;
  RETURN json_build_object('success', false, 'error', 'Erro interno. Tente novamente.');
END;
$function$
