"},{"function_name":"dinglo_resgatar_cupom","definition":"CREATE OR REPLACE FUNCTION public.dinglo_resgatar_cupom(p_codigo text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_cupom RECORD;
  v_user_id UUID := auth.uid();
  v_ja_usou BOOLEAN;
  v_plano_anterior TEXT;
BEGIN
  -- 1. Find the coupon
  SELECT * INTO v_cupom
  FROM dinglo_cupons
  WHERE UPPER(codigo) = UPPER(TRIM(p_codigo))
  LIMIT 1;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'Cupom não encontrado');
  END IF;

  -- 2. Check if active
  IF NOT v_cupom.ativo THEN
    RETURN jsonb_build_object('success', false, 'error', 'Este cupom não está mais ativo');
  END IF;

  -- 3. Check expiry
  IF v_cupom.validade IS NOT NULL AND v_cupom.validade < NOW() THEN
    RETURN jsonb_build_object('success', false, 'error', 'Este cupom expirou');
  END IF;

  -- 4. Check max uses
  IF v_cupom.max_usos IS NOT NULL AND v_cupom.usos_count >= v_cupom.max_usos THEN
    RETURN jsonb_build_object('success', false, 'error', 'Este cupom atingiu o limite de usos');
  END IF;

  -- 5. Check if user already used this coupon
  SELECT EXISTS(
    SELECT 1 FROM dinglo_cupom_usos WHERE cupom_id = v_cupom.id AND user_id = v_user_id
  ) INTO v_ja_usou;

  IF v_ja_usou THEN
    RETURN jsonb_build_object('success', false, 'error', 'Você já utilizou este cupom');
  END IF;

  -- 6. Get current plan
  SELECT plano INTO v_plano_anterior
  FROM dinglo_plano_usuario
  WHERE user_id = v_user_id;

  IF v_plano_anterior IS NULL THEN
    v_plano_anterior := 'basico';
  END IF;

  -- 7. Calculate end date
  DECLARE
    v_data_fim TIMESTAMPTZ := NULL;
    v_plano_novo TEXT := COALESCE(v_cupom.plano_concedido, 'plus');
  BEGIN
    IF v_cupom.duracao_dias IS NOT NULL AND v_cupom.duracao_dias > 0 THEN
      v_data_fim := NOW() + (v_cupom.duracao_dias || ' days')::INTERVAL;
    END IF;

    -- 8. Update/insert user plan
    INSERT INTO dinglo_plano_usuario (user_id, plano, ativo, data_inicio, data_fim)
    VALUES (v_user_id, v_plano_novo, true, NOW(), v_data_fim)
    ON CONFLICT (user_id) DO UPDATE SET
      plano = v_plano_novo,
      ativo = true,
      data_inicio = NOW(),
      data_fim = v_data_fim;

    -- 9. Record usage
    INSERT INTO dinglo_cupom_usos (cupom_id, user_id, plano_anterior, plano_novo)
    VALUES (v_cupom.id, v_user_id, v_plano_anterior, v_plano_novo);

    -- 10. Increment usage count
    UPDATE dinglo_cupons SET usos_count = usos_count + 1 WHERE id = v_cupom.id;

    RETURN jsonb_build_object(
      'success', true,
      'plano', v_plano_novo,
      'duracao_dias', v_cupom.duracao_dias,
      'descricao', v_cupom.descricao
    );
  END;
END;
$function$
"},{"function_name":"fn_set_delivery_time","definition":"CREATE OR REPLACE FUNCTION public.fn_set_delivery_time()
 RETURNS trigger
