"},{"function_name":"is_admin_of_condo","definition":"CREATE OR REPLACE FUNCTION public.is_admin_of_condo(condo_id uuid)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_role text;
  v_condo_id uuid;
BEGIN
  SELECT papel_sistema, condominio_id
    INTO v_role, v_condo_id
    FROM perfil
   WHERE id = auth.uid();

  RETURN v_condo_id = condo_id
     AND lower(v_role) = ANY(ARRAY[
       'síndico', 'sindico', 'admin',
       'síndico (a)', 'sindico (a)',
       'síndico(a)', 'sindico(a)'
     ]);
END;
$function$
"},{"function_name":"lista_add_points","definition":"CREATE OR REPLACE FUNCTION public.lista_add_points(p_user_id uuid, p_points integer)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  INSERT INTO lista_user_points (user_id, total_points, weekly_points, reports_count, rank_title)
  VALUES (p_user_id, p_points, p_points, 1, 'Iniciante')
  ON CONFLICT (user_id) DO UPDATE SET
    total_points = lista_user_points.total_points + p_points,
    weekly_points = lista_user_points.weekly_points + p_points,
    reports_count = lista_user_points.reports_count + 1,
    rank_title = CASE
      WHEN lista_user_points.total_points + p_points >= 1000 THEN 'Mestre do Preço'
      WHEN lista_user_points.total_points + p_points >= 500 THEN 'Caçador de Oferta'
      WHEN lista_user_points.total_points + p_points >= 200 THEN 'Fiscal de Preço'
      WHEN lista_user_points.total_points + p_points >= 50 THEN 'Colaborador'
      ELSE 'Iniciante'
    END,
    updated_at = now();
END;
$function$
"},{"function_name":"lista_check_price_alerts","definition":"CREATE OR REPLACE FUNCTION public.lista_check_price_alerts()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_supa_url TEXT;
  v_svc_key  TEXT;
  v_variant_id UUID;
  v_has_alerts BOOLEAN;
BEGIN
  v_supa_url := COALESCE(
    current_setting('app.settings.supabase_url', true),
    'https://avypyaxthvgaybplnwxu.supabase.co'
  );
  v_svc_key := current_setting('app.settings.service_role_key', true);

  IF v_svc_key IS NULL OR v_svc_key = '' THEN
    RAISE WARNING 'lista_check_price_alerts: service_role_key not set. Skipping.';
    RETURN NEW;
  END IF;

  SELECT variant_id INTO v_variant_id
  FROM lista_products_sku
  WHERE id = NEW.sku_id;

  IF v_variant_id IS NULL THEN
    RETURN NEW;
  END IF;

  SELECT EXISTS(
    SELECT 1
    FROM lista_price_alerts
    WHERE variant_id = v_variant_id
      AND is_active = true
      AND target_price >= NEW.price
  ) INTO v_has_alerts;

  IF v_has_alerts THEN
    PERFORM net.http_post(
      url     := v_supa_url || '/functions/v1/lista-price-alert-notify',
      headers := jsonb_build_object(
        'Content-Type',  'application/json',
        'Authorization', 'Bearer ' || v_svc_key
      ),
      body    := jsonb_build_object(
        'price_raw_id',    NEW.id,
        'sku_id',          NEW.sku_id,
        'price',           NEW.price,
        'supermarket_id',  NEW.supermarket_id
      )
    );
  END IF;

  RETURN NEW;
EXCEPTION WHEN OTHERS THEN
  RAISE WARNING 'lista_check_price_alerts failed: %', SQLERRM;
  RETURN NEW;
END;
$function$
"},{"function_name":"lista_increment_confirmations","definition":"CREATE OR REPLACE FUNCTION public.lista_increment_confirmations(p_price_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  UPDATE lista_prices_raw
  SET confirmations = confirmations + 1,
      confidence_score = LEAST(1.0, confidence_score + 0.1)
  WHERE id = p_price_id;

  -- Também atualiza confidence no prices_current
  UPDATE lista_prices_current pc
  SET confidence_score = LEAST(1.0, pc.confidence_score + 0.05)
  FROM lista_prices_raw pr
  WHERE pr.id = p_price_id
    AND pc.sku_id = pr.sku_id
    AND pc.supermarket_id = pr.supermarket_id;
END;
$function$
"},{"function_name":"lista_increment_variant_popularity","definition":"CREATE OR REPLACE FUNCTION public.lista_increment_variant_popularity(p_variant_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
