"},{"function_name":"request_password_reset_whatsapp","definition":"CREATE OR REPLACE FUNCTION public.request_password_reset_whatsapp(user_email text)
 RETURNS json
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_perfil RECORD;
  v_code TEXT;
  v_whatsapp_masked TEXT;
  v_service_key TEXT;
  v_supa_url TEXT;
  v_requester_ip inet;
  v_user_agent text;
  v_recent_count_email int;
  v_recent_count_ip int;
  v_last_code_at timestamptz;
BEGIN
  -- ============================================================
  -- CAPTURE REQUESTER INFO FOR AUDIT
  -- ============================================================
  BEGIN
    v_requester_ip := NULLIF(
      COALESCE(
        current_setting('request.headers', true)::json->>'x-forwarded-for',
        current_setting('request.headers', true)::json->>'x-real-ip',
        current_setting('request.headers', true)::json->>'cf-connecting-ip'
      ), ''
    )::inet;
  EXCEPTION WHEN OTHERS THEN
    v_requester_ip := NULL;
  END;

  BEGIN
    v_user_agent := current_setting('request.headers', true)::json->>'user-agent';
  EXCEPTION WHEN OTHERS THEN
    v_user_agent := NULL;
  END;

  -- ============================================================
  -- RATE LIMIT 1: Per-email cooldown (1 code per 5 minutes)
  -- ============================================================
  SELECT MAX(created_at) INTO v_last_code_at
  FROM password_reset_codes
  WHERE email = LOWER(TRIM(user_email))
  AND created_at > now() - interval '5 minutes';

  IF v_last_code_at IS NOT NULL THEN
    RAISE LOG 'password_reset BLOCKED (cooldown): email=% ip=% ua=% last_code=%', 
      user_email, v_requester_ip, v_user_agent, v_last_code_at;
    RETURN json_build_object(
      'success', false, 
      'error', 'Código já enviado. Aguarde 5 minutos para solicitar outro.'
    );
  END IF;

  -- ============================================================
  -- RATE LIMIT 2: Per-email daily limit (max 5 per day)
  -- ============================================================
  SELECT COUNT(*) INTO v_recent_count_email
  FROM password_reset_codes
  WHERE email = LOWER(TRIM(user_email))
  AND created_at > now() - interval '24 hours';

  IF v_recent_count_email >= 5 THEN
    RAISE LOG 'password_reset BLOCKED (daily limit): email=% count=% ip=% ua=%', 
      user_email, v_recent_count_email, v_requester_ip, v_user_agent;
    RETURN json_build_object(
      'success', false, 
      'error', 'Limite diário atingido. Tente novamente amanhã ou procure o síndico.'
    );
  END IF;

  -- ============================================================
  -- RATE LIMIT 3: Per-IP limit (max 10 requests per hour from same IP)
  -- ============================================================
  IF v_requester_ip IS NOT NULL THEN
    SELECT COUNT(*) INTO v_recent_count_ip
    FROM password_reset_codes
    WHERE requester_ip = v_requester_ip
    AND created_at > now() - interval '1 hour';

    IF v_recent_count_ip >= 10 THEN
      RAISE LOG 'password_reset BLOCKED (IP limit): ip=% count=% email=% ua=%', 
        v_requester_ip, v_recent_count_ip, user_email, v_user_agent;
      RETURN json_build_object(
        'success', false, 
        'error', 'Muitas tentativas deste dispositivo. Tente mais tarde.'
      );
    END IF;
  END IF;

  -- ============================================================
  -- 1. Find user profile
  -- ============================================================
  SELECT id, nome_completo, email, whatsapp
  INTO v_perfil
  FROM perfil
  WHERE LOWER(TRIM(email)) = LOWER(TRIM(user_email))
  AND status_aprovacao = 'aprovado'
  LIMIT 1;

  IF v_perfil IS NULL THEN
    RAISE LOG 'password_reset: profile not found for email=% ip=% ua=%', 
      user_email, v_requester_ip, v_user_agent;
    -- Don't reveal if email exists or not (security best practice)
    RETURN json_build_object(
      'success', false, 
      'error', 'Se o email estiver cadastrado, você receberá um código via WhatsApp.'
    );
  END IF;

  -- 2. Check WhatsApp
  IF v_perfil.whatsapp IS NULL OR TRIM(v_perfil.whatsapp) = '' THEN
    RETURN json_build_object('success', false, 'error', 'no_whatsapp');
  END IF;

  -- ============================================================
  -- 3. Generate 6-digit code
  -- ============================================================
  v_code := LPAD(FLOOR(RANDOM() * 1000000)::TEXT, 6, '0');

  -- 4. Invalidate previous codes for this email
  UPDATE password_reset_codes SET used = true 
  WHERE email = LOWER(TRIM(user_email)) AND used = false;

  -- 5. Save new code (expires in 5 min) with IP + user-agent
  INSERT INTO password_reset_codes (email, code, expires_at, requester_ip, user_agent)
  VALUES (LOWER(TRIM(user_email)), v_code, now() + interval '5 minutes', v_requester_ip, v_user_agent);

  -- 6. Mask WhatsApp number (show last 4 digits)
  v_whatsapp_masked := '***' || RIGHT(REGEXP_REPLACE(v_perfil.whatsapp, '\D', '', 'g'), 4);

  -- 7. Log successful reset request
  RAISE LOG 'password_reset: code sent for email=% whatsapp_masked=% ip=% ua=%', 
    user_email, v_whatsapp_masked, v_requester_ip, v_user_agent;

  -- 8. Call edge function to send WhatsApp
  v_supa_url := COALESCE(
    current_setting('app.settings.supabase_url', true),
    'https://avypyaxthvgaybplnwxu.supabase.co'
  );
  v_service_key := COALESCE(
    current_setting('app.settings.service_role_key', true),
    'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImF2eXB5YXh0aHZnYXlicGxud3h1Iiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MjIxOTk3NCwiZXhwIjoyMDg3Nzk1OTc0fQ.Y-t_4wRc8HNGPbmZJM4leUaB6m3rqMIZB75wr1VlK9s'
  );

  PERFORM net.http_post(
    url     := v_supa_url || '/functions/v1/password-reset-whatsapp',
    headers := jsonb_build_object(
      'Content-Type',  'application/json',
      'Authorization', 'Bearer ' || v_service_key
    ),
    body    := jsonb_build_object(
      'phone', v_perfil.whatsapp,
      'code', v_code,
      'name', COALESCE(SPLIT_PART(v_perfil.nome_completo, ' ', 1), 'Morador')
    )
  );

  RETURN json_build_object(
    'success', true,
    'whatsapp_masked', v_whatsapp_masked
  );

EXCEPTION WHEN OTHERS THEN
  RAISE WARNING 'request_password_reset_whatsapp failed: % | ip=% ua=%', 
    SQLERRM, v_requester_ip, v_user_agent;
  RETURN json_build_object('success', false, 'error', 'Erro interno. Tente novamente.');
END;
$function$
"},{"function_name":"setup_user_password","definition":"CREATE OR REPLACE FUNCTION public.setup_user_password(user_email text, new_password text)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'extensions'
AS $function$
DECLARE uid UUID;
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM perfil 
    WHERE email = lower(trim(user_email)) AND needs_password_setup = true
  ) THEN
    RAISE EXCEPTION 'Not eligible for password setup';
  END IF;
  IF length(new_password) < 4 THEN
    RAISE EXCEPTION 'Password too short';
  END IF;
  SELECT id INTO uid FROM auth.users WHERE email = lower(trim(user_email));
  IF uid IS NULL THEN
    RAISE EXCEPTION 'User not found in auth';
  END IF;
  UPDATE auth.users 
  SET encrypted_password = crypt(new_password, gen_salt('bf')), updated_at = now()
  WHERE id = uid;
  UPDATE perfil SET needs_password_setup = false WHERE email = lower(trim(user_email));
END;
$function$
