"},{"function_name":"tr_fn_contrato_avisar_moradores","definition":"CREATE OR REPLACE FUNCTION public.tr_fn_contrato_avisar_moradores()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF TG_OP = 'INSERT' THEN
    IF NEW.avisar_moradores = true THEN
      PERFORM public.push_notify_contrato(NEW.id, NEW.condominio_id, NEW.titulo, 'novo_contrato');
    END IF;
  ELSIF TG_OP = 'UPDATE' THEN
    IF NEW.avisar_moradores = true
       AND (OLD.titulo IS DISTINCT FROM NEW.titulo
         OR OLD.categoria IS DISTINCT FROM NEW.categoria
         OR OLD.data_validade IS DISTINCT FROM NEW.data_validade
         OR OLD.data_expedicao IS DISTINCT FROM NEW.data_expedicao
         OR OLD.avisar_moradores IS DISTINCT FROM NEW.avisar_moradores) THEN
      PERFORM public.push_notify_contrato(NEW.id, NEW.condominio_id, NEW.titulo, 'contrato_editado');
    END IF;
  END IF;
  RETURN NEW;
END;
$function$
"},{"function_name":"tr_fn_convite_created","definition":"CREATE OR REPLACE FUNCTION public.tr_fn_convite_created()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_has_whatsapp BOOLEAN;
  v_payload      JSONB;
BEGIN
  IF NEW.status <> 'active' THEN
    RETURN NEW;
  END IF;

  -- CASE 1: Portaria-created convite
  IF COALESCE(NEW.criado_por_portaria, false) = true THEN
    v_payload := jsonb_build_object(
      'action',              'portaria_created',
      'convite_id',          NEW.id,
      'resident_id',         COALESCE(NEW.resident_id::text, ''),
      'condominio_id',       NEW.condominio_id,
      'guest_name',          COALESCE(NEW.guest_name, ''),
      'visitor_phone',       COALESCE(NEW.whatsapp, ''),
      'visitor_type',        COALESCE(NEW.visitor_type, ''),
      'validity_date',       COALESCE(NEW.validity_date::text, ''),
      'qr_data',             COALESCE(NEW.qr_data, ''),
      'observacao',          COALESCE(NEW.observacao, ''),
      'bloco_destino',       COALESCE(NEW.bloco_destino, ''),
      'apto_destino',        COALESCE(NEW.apto_destino, ''),
      'morador_nome_manual', COALESCE(NEW.morador_nome_manual, '')
    );

    PERFORM net.http_post(
      url     := 'https://avypyaxthvgaybplnwxu.supabase.co/functions/v1/convite-whatsapp-notify',
      headers := jsonb_build_object(
        'Content-Type',  'application/json',
        'Authorization', 'Bearer sb_secret_BT14O-HTuhmMKKfkyWZGIw_QasPxvpE'
      ),
      body    := v_payload
    );

    RETURN NEW;
  END IF;

  -- CASE 2: Normal convite (resident-created)
  SELECT EXISTS(
    SELECT 1 FROM public.perfil
    WHERE id = NEW.resident_id
    AND (whatsapp IS NOT NULL AND whatsapp <> '')
  ) INTO v_has_whatsapp;

  IF NOT v_has_whatsapp THEN
    RAISE WARNING 'tr_fn_convite_created: no whatsapp for resident %', NEW.resident_id;
    RETURN NEW;
  END IF;

  v_payload := jsonb_build_object(
    'convite_id',     NEW.id,
    'resident_id',    NEW.resident_id,
    'condominio_id',  NEW.condominio_id,
    'guest_name',     COALESCE(NEW.guest_name, ''),
    'visitor_phone',  COALESCE(NULLIF(NEW.visitor_phone, ''), NEW.whatsapp, ''),
    'validity_date',  COALESCE(NEW.validity_date::text, ''),
    'qr_data',        COALESCE(NEW.qr_data, '')
  );

  PERFORM net.http_post(
    url     := 'https://avypyaxthvgaybplnwxu.supabase.co/functions/v1/convite-whatsapp-notify',
    headers := jsonb_build_object(
      'Content-Type',  'application/json',
      'Authorization', 'Bearer sb_secret_BT14O-HTuhmMKKfkyWZGIw_QasPxvpE'
    ),
    body    := v_payload
  );

  RETURN NEW;

EXCEPTION WHEN OTHERS THEN
  RAISE WARNING 'tr_fn_convite_created failed: %', SQLERRM;
  RETURN NEW;
END;
$function$
"},{"function_name":"tr_fn_convite_liberado","definition":"CREATE OR REPLACE FUNCTION public.tr_fn_convite_liberado()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_has_whatsapp BOOLEAN;
  v_payload      JSONB;
  v_service_key  TEXT;
BEGIN
  -- Only fire when visitante_compareceu changes from false/null to true
  IF NOT (NEW.visitante_compareceu IS TRUE
          AND (OLD.visitante_compareceu IS NOT TRUE)) THEN
    RETURN NEW;
  END IF;

  -- Check if resident has whatsapp (NOT botconversa_id)
  IF NEW.resident_id IS NOT NULL THEN
    SELECT EXISTS(
      SELECT 1 FROM public.perfil
      WHERE id = NEW.resident_id
      AND whatsapp IS NOT NULL AND whatsapp <> ''
    ) INTO v_has_whatsapp;
  ELSE
    v_has_whatsapp := false;
  END IF;

  -- For portaria-created convites without resident, we still need to notify the unit
  IF NOT v_has_whatsapp AND NOT COALESCE(NEW.criado_por_portaria, false) THEN
    RAISE WARNING 'tr_fn_convite_liberado: no whatsapp for resident % and not portaria', NEW.resident_id;
    RETURN NEW;
  END IF;

  -- Get service key
  v_service_key := coalesce(
    current_setting('app.settings.service_role_key', true),
    'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImF2eXB5YXh0aHZnYXlicGxud3h1Iiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MjIxOTk3NCwiZXhwIjoyMDg3Nzk1OTc0fQ.Y-t_4wRc8HNGPbmZJM4leUaB6m3rqMIZB75wr1VlK9s'
  );

  -- Build payload with all needed fields
  v_payload := jsonb_build_object(
    'action',              'entry_released',
    'convite_id',          NEW.id,
    'resident_id',         COALESCE(NEW.resident_id::text, ''),
    'condominio_id',       NEW.condominio_id,
    'guest_name',          COALESCE(NEW.guest_name, ''),
    'visitor_phone',       COALESCE(NEW.visitor_phone, ''),
    'visitor_type',        COALESCE(NEW.visitor_type, ''),
    'validity_date',       COALESCE(NEW.validity_date::text, ''),
    'qr_data',             COALESCE(NEW.qr_data, ''),
    'created_at',          COALESCE(NEW.created_at::text, ''),
    'liberado_em',         COALESCE(NEW.liberado_em::text, ''),
    'criado_por_portaria', COALESCE(NEW.criado_por_portaria, false),
    'bloco_destino',       COALESCE(NEW.bloco_destino, ''),
    'apto_destino',        COALESCE(NEW.apto_destino, '')
  );

  -- Call Edge Function via pg_net
  PERFORM net.http_post(
    url     := 'https://avypyaxthvgaybplnwxu.supabase.co/functions/v1/convite-whatsapp-notify',
    headers := jsonb_build_object(
      'Content-Type',  'application/json',
      'Authorization', 'Bearer ' || v_service_key
    ),
    body    := v_payload
  );

  RETURN NEW;

EXCEPTION WHEN OTHERS THEN
  RAISE WARNING 'tr_fn_convite_liberado failed: %', SQLERRM;
  RETURN NEW;
END;
$function$
"},{"function_name":"tr_fn_documento_avisar_moradores","definition":"CREATE OR REPLACE FUNCTION public.tr_fn_documento_avisar_moradores()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  -- On INSERT: notify if avisar_moradores is true
  IF TG_OP = 'INSERT' AND NEW.avisar_moradores = true THEN
    PERFORM public.push_notify_documento(
      p_documento_id  := NEW.id,
      p_condominio_id := NEW.condominio_id,
      p_titulo        := NEW.titulo,
      p_tipo_evento   := 'novo_documento'
    );
  END IF;

  -- On UPDATE: notify if avisar_moradores is true AND content changed
  IF TG_OP = 'UPDATE' AND NEW.avisar_moradores = true THEN
    IF (NEW.titulo IS DISTINCT FROM OLD.titulo)
       OR (NEW.categoria IS DISTINCT FROM OLD.categoria)
       OR (NEW.data_validade IS DISTINCT FROM OLD.data_validade)
       OR (NEW.data_expedicao IS DISTINCT FROM OLD.data_expedicao)
       OR (NEW.arquivo_url IS DISTINCT FROM OLD.arquivo_url)
       OR (NEW.descricao IS DISTINCT FROM OLD.descricao) THEN
      PERFORM public.push_notify_documento(
        p_documento_id  := NEW.id,
        p_condominio_id := NEW.condominio_id,
        p_titulo        := NEW.titulo,
        p_tipo_evento   := 'documento_editado'
      );
    END IF;
  END IF;

  RETURN NEW;
END;
$function$
"},{"function_name":"tr_fn_encomenda_arrived","definition":"CREATE OR REPLACE FUNCTION public.tr_fn_encomenda_arrived()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  -- Use bloco/apto directly from the encomenda record (not from perfil)
  -- Skip notification if both bloco and apto are empty/null
  IF COALESCE(NEW.bloco, '') = '' AND COALESCE(NEW.apto, '') = '' THEN
    RAISE WARNING 'tr_fn_encomenda_arrived: skipping push — no bloco/apto on encomenda %', NEW.id;
    RETURN NEW;
  END IF;

  PERFORM public.push_notify_parcel(
    p_parcel_id  := NEW.id,
    p_event      := 'arrived',
    p_condominio := NEW.condominio_id,
    p_bloco      := COALESCE(NEW.bloco, ''),
    p_apto       := COALESCE(NEW.apto, ''),
    p_tipo       := COALESCE(NEW.tipo, 'pacote')
  );

  RETURN NEW;
END;
$function$
"},{"function_name":"tr_fn_encomenda_delivered","definition":"CREATE OR REPLACE FUNCTION public.tr_fn_encomenda_delivered()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  -- Only fire when transitioning to delivered
  IF NEW.status <> 'delivered' OR OLD.status = 'delivered' THEN
    RETURN NEW;
  END IF;

  -- Skip if silent discharge
  IF COALESCE(NEW.silent_discharge, false) THEN
    RETURN NEW;
  END IF;

  -- Use bloco/apto directly from the encomenda record (not from perfil)
  -- Skip notification if both bloco and apto are empty/null
  IF COALESCE(NEW.bloco, '') = '' AND COALESCE(NEW.apto, '') = '' THEN
    RAISE WARNING 'tr_fn_encomenda_delivered: skipping push — no bloco/apto on encomenda %', NEW.id;
    RETURN NEW;
  END IF;

  PERFORM public.push_notify_parcel(
    p_parcel_id  := NEW.id,
    p_event      := 'delivered',
    p_condominio := NEW.condominio_id,
    p_bloco      := COALESCE(NEW.bloco, ''),
    p_apto       := COALESCE(NEW.apto, ''),
    p_tipo       := COALESCE(NEW.tipo, 'pacote'),
    p_picked_by  := NEW.picked_up_by_name
  );

  RETURN NEW;
END;
$function$
