"},{"function_name":"tr_fn_perfil_welcome","definition":"CREATE OR REPLACE FUNCTION public.tr_fn_perfil_welcome()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_condo_nome TEXT;
  v_service_key TEXT;
  v_cod_interno_1 TEXT;
  v_cod_interno_2 TEXT;
  v_msg1 TEXT;
  v_msg2 TEXT;
BEGIN
  -- Only fire when botconversa_id is set for the FIRST time (NULL -> non-NULL)
  IF OLD.botconversa_id IS NOT NULL THEN
    RETURN NEW;
  END IF;
  IF NEW.botconversa_id IS NULL OR TRIM(NEW.botconversa_id) = '' THEN
    RETURN NEW;
  END IF;

  -- Check if user opted out of WhatsApp notifications
  IF NEW.notificacoes_whatsapp IS FALSE THEN
    RETURN NEW;
  END IF;

  -- 1. Get condominium name
  SELECT nome INTO v_condo_nome
  FROM public.condominios WHERE id = NEW.condominio_id LIMIT 1;

  -- 2. Generate random 5-char codes (anti-ban for Meta)
  v_cod_interno_1 := substr(md5(random()::text), 1, 5);
  v_cod_interno_2 := substr(md5(random()::text || clock_timestamp()::text), 1, 5);

  -- 3. Build message 1 — Welcome
  v_msg1 := '😀 ' || COALESCE(v_condo_nome, 'Condomínio') || E'\n\n'
    || 'Olá ' || COALESCE(SPLIT_PART(NEW.nome_completo, ' ', 1), 'Morador') || ', seu cadastro foi feito com sucesso.' || E'\n\n'
    || 'Em breve o Adm/Síndico do ' || COALESCE(v_condo_nome, 'Condomínio') || ' irá liberar seu acesso.' || E'\n\n'
    || 'Condomeet agradece!' || E'\n'
    || 'Cód interno: ' || v_cod_interno_1;

  -- 4. Build message 2 — App info (static)
  v_msg2 := 'Ah, esse é número do aplicativo Condomeet.' || E'\n\n'
    || 'Cadastre nosso número no seu celular!' || E'\n\n'
    || 'Se precisar falar com o suporte do aplicativo Condomeet, cadastre no seu celular para não perder informação.' || E'\n\n'
    || 'Não temos informações internas do Condomínio.' || E'\n\n'
    || 'Se quiser saber das nossas novidades, siga a gente:' || E'\n\n'
