"},{"function_name":"tr_fn_reserva_status_changed","definition":"CREATE OR REPLACE FUNCTION public.tr_fn_reserva_status_changed()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_service_key TEXT;
  v_area_nome TEXT;
  v_action TEXT;
BEGIN
  -- Only fire when status actually changes
  IF OLD.status = NEW.status THEN
    RETURN NEW;
  END IF;

  -- Only notify for approved or rejected
  IF NEW.status = 'aprovado' OR NEW.status = 'approved' THEN
    v_action := 'approved';
  ELSIF NEW.status = 'recusado' OR NEW.status = 'rejected' THEN
    v_action := 'rejected';
  ELSE
    RETURN NEW;
  END IF;

  SELECT nome INTO v_area_nome FROM public.areas_comuns WHERE id = NEW.area_id;

  v_service_key := coalesce(
    current_setting('app.settings.service_role_key', true),
    'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImF2eXB5YXh0aHZnYXlicGxud3h1Iiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MjIxOTk3NCwiZXhwIjoyMDg3Nzk1OTc0fQ.Y-t_4wRc8HNGPbmZJM4leUaB6m3rqMIZB75wr1VlK9s'
  );

  PERFORM net.http_post(
    url     := coalesce(current_setting('app.settings.supabase_url', true), 'https://avypyaxthvgaybplnwxu.supabase.co') || '/functions/v1/reserva-notify',
    headers := jsonb_build_object('Content-Type', 'application/json', 'Authorization', 'Bearer ' || v_service_key),
    body    := jsonb_build_object(
      'action',       v_action,
      'reserva_id',   NEW.id,
      'user_id',      NEW.user_id,
      'condominio_id', NEW.condominio_id,
      'area_nome',    COALESCE(v_area_nome, ''),
      'data_reserva', COALESCE(NEW.data_reserva::text, '')
    )
  );

  RETURN NEW;
EXCEPTION WHEN OTHERS THEN
