"},{"function_name":"tr_fn_resolve_botconversa","definition":"CREATE OR REPLACE FUNCTION public.tr_fn_resolve_botconversa()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_service_key TEXT;
  v_whatsapp TEXT;
