  -- Determine the whatsapp value to use
  v_whatsapp := NEW.whatsapp;

  -- Only proceed if whatsapp is non-empty
  IF v_whatsapp IS NULL OR TRIM(v_whatsapp) = '' THEN
    RETURN NEW;
  END IF;

  -- On UPDATE, only proceed if whatsapp actually changed
  IF TG_OP = 'UPDATE' THEN
    IF OLD.whatsapp IS NOT DISTINCT FROM NEW.whatsapp THEN
      RETURN NEW;
    END IF;
  END IF;

  -- Get service key for auth
  v_service_key := coalesce(
    current_setting('app.settings.service_role_key', true),
    'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImF2eXB5YXh0aHZnYXlicGxud3h1Iiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MjIxOTk3NCwiZXhwIjoyMDg3Nzk1OTc0fQ.Y-t_4wRc8HNGPbmZJM4leUaB6m3rqMIZB75wr1VlK9s'
  );

  BEGIN
    PERFORM net.http_post(
      url     := 'https://avypyaxthvgaybplnwxu.supabase.co/functions/v1/botconversa-resolve-subscriber',
      headers := jsonb_build_object(
        'Content-Type', 'application/json',
        'Authorization', 'Bearer ' || v_service_key
      ),
      body    := jsonb_build_object(
        'perfil_id', NEW.id::text,
        'whatsapp', v_whatsapp,
        'nome_completo', COALESCE(NEW.nome_completo, '')
      )
    );
  EXCEPTION WHEN OTHERS THEN
    RAISE WARNING 'botconversa-resolve-subscriber call failed: %', SQLERRM;
  END;

  RETURN NEW;
END;
