"},{"function_name":"verify_reset_code_and_update_password","definition":"CREATE OR REPLACE FUNCTION public.verify_reset_code_and_update_password(user_email text, reset_code text, new_password text)
 RETURNS json
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'extensions'
AS $function$
DECLARE
  v_code_record RECORD;
  v_uid UUID;
BEGIN
  -- 1. Validate password
  IF LENGTH(new_password) < 4 THEN
    RETURN json_build_object('success', false, 'error', 'Senha deve ter no mínimo 4 dígitos.');
  END IF;

  -- 2. Find valid code
  SELECT id INTO v_code_record
  FROM password_reset_codes
  WHERE email = LOWER(TRIM(user_email))
    AND code = reset_code
    AND used = false
    AND expires_at > now()
  ORDER BY created_at DESC
  LIMIT 1;

  IF v_code_record IS NULL THEN
    RETURN json_build_object('success', false, 'error', 'Código inválido ou expirado.');
  END IF;

  -- 3. Find auth user
  SELECT id INTO v_uid FROM auth.users WHERE email = LOWER(TRIM(user_email));
  IF v_uid IS NULL THEN
    RETURN json_build_object('success', false, 'error', 'Usuário não encontrado.');
  END IF;

  -- 4. Update password
  UPDATE auth.users
  SET encrypted_password = crypt(new_password, gen_salt('bf')),
      updated_at = now()
  WHERE id = v_uid;

  -- 5. Mark code as used
  UPDATE password_reset_codes SET used = true WHERE id = v_code_record.id;

  -- 6. Clear needs_password_setup if set
  UPDATE perfil SET needs_password_setup = false WHERE email = LOWER(TRIM(user_email)) AND needs_password_setup = true;

  RETURN json_build_object('success', true);

EXCEPTION WHEN OTHERS THEN
  RAISE WARNING 'verify_reset_code_and_update_password failed: %', SQLERRM;
  RETURN json_build_object('success', false, 'error', 'Erro interno. Tente novamente.');
END;
$function$
"}]
